/**
 * Processor node that performs CRUD operations on xycoords.
 *
 * Uses In3AnyOut2 pattern (fires on ANY input change). Per-channel identity
 * tracking prevents stale cached values from re-triggering operations.
 * Accesses DAO via XYCoordsPersistence (Koin).
 */
object XYCoordRepositoryCodeNode : CodeNodeDefinition {
    override val name = "XYCoordRepository"
    override val category = CodeNodeType.TRANSFORMER
    override val description = "Performs save, update, and remove operations on xycoords"
    override val inputPorts = listOf(
        PortSpec("save", XYCoord::class),
        PortSpec("update", XYCoord::class),
        PortSpec("remove", XYCoord::class)
    )
    override val outputPorts = listOf(
        PortSpec("result", List::class),
        PortSpec("error", String::class)
    )
    override val anyInput = true

    override fun createRuntime(name: String): NodeRuntime {
        val defaultEntity = XYCoord(X = 0.0, Y = 0.0)
        var lastSaveRef: XYCoord = defaultEntity
        var lastUpdateRef: XYCoord = defaultEntity
        var lastRemoveRef: XYCoord = defaultEntity

        return CodeNodeFactory.createIn3AnyOut2Processor<XYCoord, XYCoord, XYCoord, List<XYCoord>, String>(
