            initialValue2 = defaultEntity,
            initialValue3 = defaultEntity,
            process = { save, update, remove ->
                try {
                    val repo = XYCoordRepository(XYCoordsPersistence.dao)
                    val isFreshSave = save !== lastSaveRef
                    val isFreshUpdate = update !== lastUpdateRef
                    val isFreshRemove = remove !== lastRemoveRef

                    suspend fun emitCurrentList(): ProcessResult2<List<XYCoord>, String> {
                        val list = repo.observeAll().first().map { it.toXYCoord() }
                        return ProcessResult2.first(list)
                    }

                    when {
                        isFreshSave -> {
                            lastSaveRef = save
                            repo.save(save.toEntity())
                            emitCurrentList()
                        }
                        isFreshUpdate -> {
                            lastUpdateRef = update
                            repo.update(update.toEntity())
                            emitCurrentList()
                        }
                        isFreshRemove -> {
                            lastRemoveRef = remove
                            repo.remove(remove.toEntity())
